import{f as o,o as r,c as s,a9 as n}from"./chunks/framework.BSdZLMbP.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段14-面试真题与系统设计.md","filePath":"S6-Go/阶段14-面试真题与系统设计.md","lastUpdated":1780660866000}'),e={name:"S6-Go/阶段14-面试真题与系统设计.md"};function a(i,t,l,g,d,c){return r(),s("div",null,[...t[0]||(t[0]=[n('<h2 id="🏆-阶段十四-面试真题与系统设计题" tabindex="-1">🏆 阶段十四：面试真题与系统设计题 <a class="header-anchor" href="#🏆-阶段十四-面试真题与系统设计题" aria-label="Permalink to &quot;🏆 阶段十四：面试真题与系统设计题&quot;">​</a></h2><h3 id="_14-1-大厂真题精选" tabindex="-1">14.1 大厂真题精选 <a class="header-anchor" href="#_14-1-大厂真题精选" aria-label="Permalink to &quot;14.1 大厂真题精选&quot;">​</a></h3><h4 id="q55-设计一个短链接生成系统-如-t-cn-要求高并发、低延迟。" tabindex="-1">Q55: 设计一个短链接生成系统（如 t.cn），要求高并发、低延迟。 <a class="header-anchor" href="#q55-设计一个短链接生成系统-如-t-cn-要求高并发、低延迟。" aria-label="Permalink to &quot;Q55: 设计一个短链接生成系统（如 t.cn），要求高并发、低延迟。&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：Hash 算法、发号器、缓存策略、防冲突。</p><p><strong>💡 记忆关键词</strong>：发号器、62 进制、Redis 缓存、302 跳转</p><p><strong>答案要点</strong>：</p><ul><li><strong>发号方案</strong>：使用 Redis <code>INCR</code> 或 Snowflake 算法生成唯一 ID，转为 62 进制短码。</li><li><strong>存储</strong>：MySQL 存映射关系，Redis 缓存热点短链（TTL 1 天）。</li><li><strong>跳转</strong>：301（永久，浏览器缓存）vs 302（临时，可统计点击）。推荐 302 便于数据分析。</li><li><strong>防刷</strong>：同一域名限制生成频率，恶意域名黑名单拦截。</li></ul><h4 id="q56-如何实现一个分布式定时任务调度中心" tabindex="-1">Q56: 如何实现一个分布式定时任务调度中心？ <a class="header-anchor" href="#q56-如何实现一个分布式定时任务调度中心" aria-label="Permalink to &quot;Q56: 如何实现一个分布式定时任务调度中心？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：时间轮、一致性 Hash、Leader 选举、失败重试。</p><p><strong>💡 记忆关键词</strong>：时间轮调度、Leader 选举、一致性分配、指数退避</p><p><strong>答案要点</strong>：</p><ul><li><strong>调度器</strong>：使用 <code>cron</code> 表达式解析，基于时间轮（Time Wheel）或延迟队列触发。</li><li><strong>执行器</strong>：多节点部署，通过一致性 Hash 或轮询分配任务，避免重复执行。</li><li><strong>高可用</strong>：使用 etcd 或 Redis 实现 Leader 选举，主节点故障自动切换。</li><li><strong>监控</strong>：任务执行日志、成功率、耗时统计，失败自动重试（指数退避）。</li></ul><h3 id="_14-2-场景设计题" tabindex="-1">14.2 场景设计题 <a class="header-anchor" href="#_14-2-场景设计题" aria-label="Permalink to &quot;14.2 场景设计题&quot;">​</a></h3><h4 id="q57-设计一个支持千万级用户的在线状态查询系统。" tabindex="-1">Q57: 设计一个支持千万级用户的在线状态查询系统。 <a class="header-anchor" href="#q57-设计一个支持千万级用户的在线状态查询系统。" aria-label="Permalink to &quot;Q57: 设计一个支持千万级用户的在线状态查询系统。&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：Bitmap、Redis Set、WebSocket 推送、分库分表。</p><p><strong>💡 记忆关键词</strong>：Bitmap 存储、WebSocket 推送、心跳机制、批量查询</p><p><strong>答案要点</strong>：</p><ul><li><strong>状态存储</strong>：Redis Bitmap 按天记录在线状态（<code>SETBIT uid 1</code>），空间极小（千万用户约 1.2MB/天）。</li><li><strong>实时推送</strong>：WebSocket 长连接维护用户会话，下线时更新状态并广播好友列表。</li><li><strong>查询优化</strong>：批量查询使用 <code>BITFIELD</code> 或 <code>MGET</code>；历史状态归档至 ClickHouse 或 ES。</li><li><strong>一致性</strong>：网络抖动导致状态不准，引入心跳机制（30s 无心跳判定离线）。</li></ul><h4 id="q58-如何设计一个高可用的文件上传服务-支持断点续传、秒传。" tabindex="-1">Q58: 如何设计一个高可用的文件上传服务？支持断点续传、秒传。 <a class="header-anchor" href="#q58-如何设计一个高可用的文件上传服务-支持断点续传、秒传。" aria-label="Permalink to &quot;Q58: 如何设计一个高可用的文件上传服务？支持断点续传、秒传。&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：分片上传、MD5 校验、对象存储、CDN 加速。</p><p><strong>💡 记忆关键词</strong>：MD5 秒传、分片上传、预签名 URL、CDN 加速</p><p><strong>答案要点</strong>：</p><ul><li><strong>秒传</strong>：计算文件 MD5，查询是否已存在，存在则直接返回 URL。</li><li><strong>分片</strong>：前端切片（如 5MB/片），并发上传，服务端合并分片。</li><li><strong>存储</strong>：直传 OSS/S3（预签名 URL），避免流量经过业务服务器。</li><li><strong>高可用</strong>：多可用区部署，CDN 边缘缓存热点文件，上传进度持久化至 Redis。</li></ul><hr>',28)])])}const _=o(e,[["render",a]]);export{h as __pageData,_ as default};
